import java.time.Duration;
import java.util.Optional;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Profile;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Component;
import org.springframework.web.reactive.function.client.WebClient;

import io.github.resilience4j.circuitbreaker.CircuitBreaker;
import io.github.resilience4j.circuitbreaker.CircuitBreakerRegistry;
import lombok.extern.slf4j.Slf4j;

@Slf4j
@Component
@Profile("!backup")
public class RMUpstreamHealthProbe {

    private final CircuitBreakerRegistry circuitBreakerRegistry;
    private final WebClient webClient;

    @Value("${file.ipath.load_balancer_server}")
    private String iHost;

    @Value("${file.epath.load_balancer_server}")
    private String eHost;

    @Value("${request.file.url.iPath}")
    private String iPath;

    @Value("${request.file.url.ePath}")
    private String ePath;

    public RMUpstreamHealthProbe(CircuitBreakerRegistry circuitBreakerRegistry, WebClient webClient) {
        this.circuitBreakerRegistry = circuitBreakerRegistry;
        this.webClient = webClient;
    }

    /**
     * 30珥� 二쇨린濡� CB OPEN �긽�깭�쓽 �뾽�뒪�듃由� 媛��슜�꽦�쓣 �솗�씤�븳�떎.
     * 5xx媛� �븘�땶 �쓳�떟(200, 404 �벑)��� LB �씪�슦�똿�씠 �꽦怨듯뻽�쓬�쓣 �쓽誘명븯誘�濡�
     * cb.transitionToHalfOpenState()瑜� �닔�룞 �샇異쒗븯�뿬 CBListenerConfig媛� 由ъ뒪�꼫瑜� �옱�떆�옉�븯�룄濡� �븳�떎.
     */
    @Scheduled(fixedDelay = 30_000, initialDelay = 30_000)
    public void probe() {
        probeOne("filesync-main",     iHost + iPath);
        probeOne("filesync-recovery", eHost + ePath);
    }

    // package-private: �뀒�뒪�듃�뿉�꽌 吏곸젒 �샇異� 媛��뒫
    void probeOne(String cbName, String baseUrl) {
        CircuitBreaker cb = circuitBreakerRegistry.circuitBreaker(cbName);
        if (cb.getState() != CircuitBreaker.State.OPEN) {
            return;
        }

        String url = baseUrl + "?filename=_probe&filepath=/probe";
        Optional<Integer> status = executeProbe(url);

        // 5xx(�꽌踰� �삤瑜�, LB �씤�뒪�꽩�뒪 �뾾�쓬 �룷�븿) �삉�뒗 �꽕�듃�썙�겕 �삁�쇅�뒗 �떎�슫�쑝濡� �뙋�젙
        boolean isUp = status.isPresent() && status.get() < 500;

        if (isUp) {
            log.info("[HealthProbe-{}] �뾽�뒪�듃由� 蹂듦뎄 媛먯�� (status={}) �넂 HALF_OPEN �쟾�솚", cbName, status.get());
            cb.transitionToHalfOpenState();
        } else {
            log.debug("[HealthProbe-{}] �뾽�뒪�듃由� �떎�슫 (status={})", cbName, status.orElse(null));
        }
    }

    // package-private: �뀒�뒪�듃�뿉�꽌 �삤踰꾨씪�씠�뱶 媛��뒫
    Optional<Integer> executeProbe(String url) {
        try {
            return webClient.head()
                .uri(url)
                .exchangeToMono(r -> reactor.core.publisher.Mono.just(r.statusCode().value()))
                .timeout(Duration.ofSeconds(5))
                .blockOptional();
        } catch (Exception e) {
            log.debug("[HealthProbe] probe �삁�쇅: url={}, cause={}", url, e.getMessage());
            return Optional.empty();
        }
    }
}
