@Slf4j
@Service
@RequiredArgsConstructor
@Profile("!backup")
public class FileQBackupService {

	private final FileQBackupRepository fileQueueBackupRepository;
	private final FileQRepository fileQueueRepository;

	/**
	 * 諛깆뾽 ����긽 �뿬遺��뿉 �뵲�씪 遺꾧린 泥섎━
	 * - queueStt == BACKUP(5) : TBL_FILEQ.ETC_N_COL1�쓣 BACKUP �긽�깭濡� �뾽�뜲�씠�듃 (backupProcess �쐞�엫)
	 * - 洹� �쇅 : FileQBackup �젅肄붾뱶�쓽 �긽�깭(queueStt)瑜� �뾽�뜲�씠�듃�븯怨�,
	 *           �셿猷� �긽�깭�뿉 �뵲�씪 諛깆뾽 �셿猷뚯씪(bakDate) �삉�뒗 蹂듭썝�씪(rcvDate)�쓣 湲곕줉
	 * @param int cNo      �뙆�씪 怨좎쑀踰덊샇
	 * @param int queueStt 泥섎━�븷 �걧 �긽�깭 肄붾뱶
	 **/
	@Transactional
	public void updateBackupRecovery(int cNo, int queueStt) {

		// 諛깆뾽����긽�씤 寃쎌슦 �뾽�뜲�씠�듃 泥섎━
		if(queueStt == QueueStatusEunm.BACKUP.getQueueStt()) {
			backupProcess(cNo);
			return;
		}

		// find �넂 set �넂 save ����떊 吏곸젒 UPDATE濡� JPA 罹먯떆/�듃�옖�옲�뀡 ����씠諛� 臾몄젣 諛⑹��
		int updated;
		if(queueStt == QueueStatusEunm.BACKUP_SUCCESS.getQueueStt()) {
