			updated = fileQueueBackupRepository.updateQueueSttAndBakDate(cNo, queueStt, LocalDateTime.now());
		} else if(queueStt == QueueStatusEunm.IRECOVERY_BACKUP.getQueueStt()
				|| queueStt == QueueStatusEunm.ERECOVERY_BACKUP.getQueueStt()) {
			// `�궡遺�留�/�씤�꽣�꽬留� 蹂듭썝 �걧` �셿猷�: rcvDate 湲곕줉
			updated = fileQueueBackupRepository.updateQueueSttAndRcvDate(cNo, queueStt, LocalDateTime.now());
		} else {
			updated = fileQueueBackupRepository.updateQueueStt(cNo, queueStt);
		}

		if(updated == 0) {
			throw new IllegalStateException("[updateBackupRecovery] �젅肄붾뱶 �뾾�쓬: cNo=" + cNo + ", queueStt=" + queueStt);
		}
	}

	/**
	 * 諛깆뾽 �떊�샇 �꽕�젙 ��� TBL_FILEQ.ETC_N_COL1�쓣 BACKUP(5) �긽�깭濡� �뾽�뜲�씠�듃
